line1 = input().split()
n, W = int(line1[0]), int(line1[1])
if n == 0 or W == 0:
    print(0)
else:
    weights = list(map(int, input().split()))
    values = list(map(int, input().split()))
    dp = [0] * (W + 1)
    for i in range(n):
        for w in range(W, weights[i]-1, -1):
            dp[w] = max(dp[w], dp[w-weights[i]] + values[i])
    print(dp[W])

